const LOGO_SRC = "data:image/jpeg;base64,";
document.addEventListener('DOMContentLoaded', () => {
  document.querySelectorAll('#logoImg,#sidebarLogoImg').forEach(img => img.src = LOGO_SRC);
});
 
/* ── SAIRAM POLYTECHNIC COLLEGE coords ── */
const SAIRAM = { lat: 13.0358, lng: 80.0911 };
 
/* ── STATE ── */
let vehicles = JSON.parse(localStorage.getItem('fx_v')) || [];
let drivers  = JSON.parse(localStorage.getItem('fx_d')) || [];
let routes   = JSON.parse(localStorage.getItem('fx_r')) || [];
let issues   = JSON.parse(localStorage.getItem('fx_i')) || [];
let actLog   = JSON.parse(localStorage.getItem('fx_l')) || [];
 
/* ── SAVE ── */
function save() {
  localStorage.setItem('fx_v', JSON.stringify(vehicles));
  localStorage.setItem('fx_d', JSON.stringify(drivers));
  localStorage.setItem('fx_r', JSON.stringify(routes));
  localStorage.setItem('fx_i', JSON.stringify(issues));
  localStorage.setItem('fx_l', JSON.stringify(actLog.slice(0,50)));
}
 
/* ── THEME ── */
function applyTheme(theme) {
  document.documentElement.setAttribute('data-theme', theme);
  localStorage.setItem('fx_theme', theme);
  const icon = theme === 'dark' ? '☀️' : '🌙';
  document.querySelectorAll('.theme-toggle').forEach(b => b.textContent = icon);
  if (trendChart) { trendChart.destroy(); donutChart.destroy(); driverChart.destroy(); trendChart=donutChart=driverChart=null; initCharts(); }
}
function toggleTheme() {
  const cur = document.documentElement.getAttribute('data-theme') || 'light';
  applyTheme(cur === 'light' ? 'dark' : 'light');
}
 
/* ── TOAST ── */
function toast(msg, type='info') {
  const el = document.createElement('div');
  el.className = `toast-item ${type}`;
  el.textContent = msg;
  document.getElementById('toast').appendChild(el);
  setTimeout(() => el.remove(), 3600);
}
 
/* ── ACTIVITY LOG ── */
function logActivity(text, type='act-info') {
  const time = new Date().toLocaleTimeString('en-US',{hour:'2-digit',minute:'2-digit'});
  actLog.unshift({text, type, time});
  renderActivity();
  save();
}
function renderActivity() {
  const feed = document.getElementById('activityFeed');
  if (!feed) return;
  if (!actLog.length) {
    feed.innerHTML='<li class="activity-item act-info"><div class="act-dot"></div><div class="act-body"><div class="act-text">No activity yet</div></div></li>';
    return;
  }
  feed.innerHTML = actLog.slice(0,12).map(a =>
    `<li class="activity-item ${a.type}"><div class="act-dot"></div><div class="act-body"><div class="act-text">${a.text}</div><div class="act-time">${a.time}</div></div></li>`
  ).join('');
}
 
/* ── AUTH ── */
function login() {
  const u = document.getElementById('username').value.trim();
  const p = document.getElementById('password').value;
  if (u==='admin' && p==='1234') {
    localStorage.setItem('fx_auth','1');
    document.getElementById('loginPage').style.display='none';
    document.getElementById('app').style.display='block';
    initApp();
  } else {
    toast('Invalid credentials. Try admin / 1234','error');
    document.getElementById('password').value='';
  }
}
function logout() { localStorage.removeItem('fx_auth'); location.reload(); }
document.addEventListener('keydown', e => {
  if (e.key==='Enter' && document.getElementById('loginPage').style.display!=='none') login();
});
 
/* ── SECTION SWITCH ── */
function showSection(id, el) {
  document.querySelectorAll('.section').forEach(s => s.classList.remove('active'));
  document.querySelectorAll('.nav-item').forEach(n => n.classList.remove('active'));
  document.getElementById(id).classList.add('active');
  if (el) el.classList.add('active');
  if (id==='tracking') initMap();
}
 
/* ── VEHICLES ── */
function addVehicle() {
  const num=document.getElementById('vNum').value.trim(), type=document.getElementById('vType').value;
  const cap=document.getElementById('vCap').value, status=document.getElementById('vStatus').value;
  if (!num||!type){toast('Vehicle number and type are required','warning');return;}
  vehicles.push({num,type,cap:cap||'—',status,id:Date.now()});
  save();renderVehicles();renderDashboard();updateDropdowns();
  logActivity(`Vehicle ${num} (${type}) added`,'act-add');
  toast(`Vehicle ${num} added`,'success');
  document.getElementById('vNum').value='';document.getElementById('vCap').value='';document.getElementById('vType').value='';
}
function deleteVehicle(i) {
  const v=vehicles[i];vehicles.splice(i,1);
  save();renderVehicles();renderDashboard();updateDropdowns();
  logActivity(`Vehicle ${v.num} removed`,'act-delete');toast(`Vehicle ${v.num} removed`,'error');
}
function renderVehicles() {
  const tbody=document.getElementById('vehicleTableBody'),count=document.getElementById('vTableCount');
  if(!tbody)return;
  count.textContent=vehicles.length+' vehicle'+(vehicles.length!==1?'s':'');
  if(!vehicles.length){tbody.innerHTML='<tr><td colspan="6"><div class="empty-state"><span class="empty-icon">🚚</span><div class="empty-text">No vehicles added yet</div></div></td></tr>';return;}
  tbody.innerHTML=vehicles.map((v,i)=>`
    <tr><td style="color:var(--text-muted);font-size:11px">${i+1}</td><td><strong>${v.num}</strong></td><td>${v.type}</td><td>${v.cap}</td>
    <td><span class="badge badge-${v.status}">${v.status}</span></td>
    <td><button class="btn-del" onclick="deleteVehicle(${i})">✕</button></td></tr>`).join('');
}
 
/* ── DRIVERS ── */
function addDriver() {
  const name=document.getElementById('dName').value.trim(),lic=document.getElementById('dLic').value.trim();
  const phone=document.getElementById('dPhone').value.trim(),veh=document.getElementById('dVehicle').value;
  if(!name||!lic||!phone){toast('Name, license and phone are required','warning');return;}
  drivers.push({name,lic,phone,vehicle:veh,id:Date.now()});
  save();renderDrivers();renderDashboard();updateDropdowns();
  logActivity(`Driver ${name} added`,'act-add');toast(`Driver ${name} added`,'success');
  ['dName','dLic','dPhone'].forEach(id=>document.getElementById(id).value='');document.getElementById('dVehicle').value='';
}
function deleteDriver(i) {
  const d=drivers[i];drivers.splice(i,1);
  save();renderDrivers();renderDashboard();updateDropdowns();
  logActivity(`Driver ${d.name} removed`,'act-delete');toast(`Driver ${d.name} removed`,'error');
}
function renderDrivers() {
  const tbody=document.getElementById('driverTableBody'),count=document.getElementById('dTableCount');
  if(!tbody)return;
  count.textContent=drivers.length+' driver'+(drivers.length!==1?'s':'');
  if(!drivers.length){tbody.innerHTML='<tr><td colspan="6"><div class="empty-state"><span class="empty-icon">👨‍✈️</span><div class="empty-text">No drivers added yet</div></div></td></tr>';return;}
  tbody.innerHTML=drivers.map((d,i)=>`
    <tr><td style="color:var(--text-muted);font-size:11px">${i+1}</td><td><strong>${d.name}</strong></td>
    <td style="font-size:11.5px;color:var(--text-sub)">${d.lic}</td><td>${d.phone}</td>
    <td style="font-size:12px">${d.vehicle||'<span style="color:var(--text-muted)">Unassigned</span>'}</td>
    <td><button class="btn-del" onclick="deleteDriver(${i})">✕</button></td></tr>`).join('');
}
 
/* ── ROUTES ── */
function addRoute() {
  const start=document.getElementById('rStart').value.trim(),end=document.getElementById('rEnd').value.trim();
  const dist=document.getElementById('rDist').value,driver=document.getElementById('rDriver').value;
  if(!start||!end){toast('Start and end locations are required','warning');return;}
  routes.push({start,end,dist:dist||'—',driver,id:Date.now()});
  save();renderRoutes();renderDashboard();updateDropdowns();
  logActivity(`Route ${start} → ${end} added`,'act-add');toast('Route added','success');
  ['rStart','rEnd','rDist'].forEach(id=>document.getElementById(id).value='');document.getElementById('rDriver').value='';
}
function deleteRoute(i) {
  const r=routes[i];routes.splice(i,1);
  save();renderRoutes();renderDashboard();
  logActivity(`Route ${r.start} → ${r.end} removed`,'act-delete');toast('Route removed','error');
}
function renderRoutes() {
  const wrap=document.getElementById('routeListWrap'),count=document.getElementById('rTableCount');
  if(!wrap)return;
  count.textContent=routes.length+' route'+(routes.length!==1?'s':'');
  if(!routes.length){wrap.innerHTML='<div class="empty-state" style="padding:40px 20px"><span class="empty-icon">🛣️</span><div class="empty-text">No routes added yet</div></div>';return;}
  wrap.innerHTML=routes.map((r,i)=>`
    <div class="route-item-card">
      <div style="width:26px;height:26px;border-radius:50%;background:rgba(45,106,143,0.12);display:flex;align-items:center;justify-content:center;font-size:12px;flex-shrink:0">🛣️</div>
      <div class="route-stops"><span class="route-stop" title="${r.start}">${r.start}</span><span class="route-arrow">→</span><span class="route-stop" title="${r.end}">${r.end}</span></div>
      ${r.dist!=='—'?`<span class="route-dist">${r.dist} km</span>`:''}
      ${r.driver?`<span class="badge badge-active" style="font-size:10.5px">${r.driver}</span>`:''}
      <button class="btn-del" onclick="deleteRoute(${i})">✕</button>
    </div>`).join('');
}
 
/* ── ISSUES ── */
function submitIssue() {
  const type=document.getElementById('issueType').value,vehicle=document.getElementById('issueVehicle').value;
  const text=document.getElementById('issueText').value.trim();
  if(!text){toast('Please describe the issue','warning');return;}
  issues.unshift({type,vehicle,text,time:new Date().toLocaleString(),id:Date.now()});
  save();renderIssues();renderDashboard();
  logActivity(`Issue reported: ${type}`,'act-warn');toast(`Issue reported: ${type}`,'warning');
  document.getElementById('issueText').value='';
}
function renderIssues() {
  const wrap=document.getElementById('issueListWrap'),count=document.getElementById('iTableCount');
  if(!wrap)return;
  count.textContent=issues.length+' issue'+(issues.length!==1?'s':'');
  if(!issues.length){wrap.innerHTML='<div class="empty-state" style="padding:40px 20px"><span class="empty-icon">✅</span><div class="empty-text">No issues reported</div></div>';return;}
  wrap.innerHTML=issues.map(iss=>`
    <div class="issue-item">
      <div class="issue-head"><span class="issue-type">⚠️ ${iss.type}</span><span class="issue-time">${iss.time}</span></div>
      ${iss.vehicle?`<div style="font-size:10.5px;color:var(--text-muted);margin-bottom:3px">Vehicle: ${iss.vehicle}</div>`:''}
      <div class="issue-text">${iss.text}</div>
    </div>`).join('');
}
 
/* ── DROPDOWNS ── */
function updateDropdowns() {
  const vOpts=vehicles.map(v=>`<option value="${v.num}">${v.num} (${v.type})</option>`).join('');
  const dOpts=drivers.map(d=>`<option value="${d.name}">${d.name}</option>`).join('');
  const dv=document.getElementById('dVehicle');if(dv)dv.innerHTML='<option value="">-- Unassigned --</option>'+vOpts;
  const rd=document.getElementById('rDriver');if(rd)rd.innerHTML='<option value="">-- No driver --</option>'+dOpts;
  const iv=document.getElementById('issueVehicle');if(iv)iv.innerHTML='<option value="">-- Select vehicle --</option>'+vOpts;
}
 
/* ── DASHBOARD ── */
function animateCount(el,target) {
  if(!el)return;const start=parseInt(el.textContent)||0,dur=500,t0=performance.now();
  (function step(now){const p=Math.min((now-t0)/dur,1);el.textContent=Math.round(start+(target-start)*p);if(p<1)requestAnimationFrame(step);})(t0);
}
function renderDashboard() {
  animateCount(document.getElementById('vCount'),vehicles.length);
  animateCount(document.getElementById('dCount'),drivers.length);
  animateCount(document.getElementById('rCount'),routes.length);
  animateCount(document.getElementById('iCount'),issues.length);
  const active=vehicles.filter(v=>v.status==='active').length;
  const idle=vehicles.filter(v=>v.status==='idle').length;
  const offline=vehicles.filter(v=>v.status==='offline').length;
  document.getElementById('activeV').textContent=active;
  document.getElementById('idleV').textContent=idle;
  document.getElementById('offlineV').textContent=offline;
  document.getElementById('activeD').textContent=Math.min(drivers.length,active);
  document.getElementById('availD').textContent=Math.max(0,drivers.length-Math.min(drivers.length,active));
  const mc=document.getElementById('vehicleMapCount');if(mc)mc.textContent=vehicles.length;
  updateCharts();
}
 
/* ── CHARTS ── */
let trendChart,donutChart,driverChart;
function isDark(){return document.documentElement.getAttribute('data-theme')==='dark';}
function chartColors(){
  return {
    grid:isDark()?'rgba(100,55,55,0.15)':'rgba(201,169,122,0.1)',
    text:isDark()?'#c9a060':'#a07840',
    bar:isDark()?'rgba(180,100,80,0.6)':'rgba(107,63,31,0.6)'
  };
}
function initCharts() {
  if(trendChart)return;
  const C=chartColors();
  Chart.defaults.font.family="'DM Sans',sans-serif";
  Chart.defaults.color=C.text;
  const days=['Mon','Tue','Wed','Thu','Fri','Sat','Sun'];
  trendChart=new Chart(document.getElementById('trendChart').getContext('2d'),{
    type:'line',
    data:{labels:days,datasets:[
      {label:'Vehicles Active',data:[2,4,3,5,4,6,vehicles.length],borderColor:'#c9a060',backgroundColor:'rgba(201,160,96,0.07)',borderWidth:2.5,tension:0.4,fill:true,pointBackgroundColor:'#c9a060',pointRadius:4,pointHoverRadius:6},
      {label:'Drivers On-duty',data:[1,3,2,4,3,5,drivers.length],borderColor:'#4a7c59',backgroundColor:'rgba(74,124,89,0.05)',borderWidth:2.5,tension:0.4,fill:true,pointBackgroundColor:'#4a7c59',pointRadius:4,pointHoverRadius:6}
    ]},
    options:{responsive:true,plugins:{legend:{position:'top',labels:{usePointStyle:true,padding:16,font:{size:11}}},tooltip:{mode:'index',intersect:false}},scales:{y:{beginAtZero:true,grid:{color:C.grid},ticks:{stepSize:1}},x:{grid:{display:false}}}}
  });
  donutChart=new Chart(document.getElementById('donutChart').getContext('2d'),{
    type:'doughnut',
    data:{labels:['Vehicles','Drivers','Routes','Issues'],datasets:[{data:[vehicles.length||1,drivers.length||1,routes.length||1,issues.length||0],backgroundColor:['rgba(201,160,96,0.85)','rgba(74,124,89,0.85)','rgba(45,106,143,0.85)','rgba(201,130,10,0.85)'],borderColor:'rgba(0,0,0,0.1)',borderWidth:3,hoverOffset:8}]},
    options:{responsive:true,cutout:'68%',plugins:{legend:{position:'bottom',labels:{usePointStyle:true,padding:13,font:{size:11}}}}}
  });
  driverChart=new Chart(document.getElementById('driverChart').getContext('2d'),{
    type:'bar',
    data:{labels:days,datasets:[{label:'Routes Completed',data:[2,5,3,7,4,6,routes.length],backgroundColor:C.bar,borderRadius:6,borderSkipped:false}]},
    options:{responsive:true,plugins:{legend:{display:false}},scales:{y:{beginAtZero:true,grid:{color:C.grid},ticks:{stepSize:1}},x:{grid:{display:false}}}}
  });
}
function updateCharts() {
  if(!trendChart||!donutChart||!driverChart)return;
  trendChart.data.datasets[0].data[6]=vehicles.length;trendChart.data.datasets[1].data[6]=drivers.length;trendChart.update('none');
  donutChart.data.datasets[0].data=[vehicles.length||1,drivers.length||1,routes.length||1,issues.length||0];donutChart.update('none');
  driverChart.data.datasets[0].data[6]=routes.length;driverChart.update('none');
}
 
/* ── MAP — Leaflet + OpenStreetMap ──
   Destination: Sairam Polytechnic College, Chennai (13.0358°N, 80.0911°E)
   - Hardcoded destination marker always visible
   - GPS or fallback to Chennai Central
   - Dashed polyline from current → college
   - Live distance + ETA (Haversine, 40 km/h avg)
   - Simulated vehicle markers with periodic drift
─────────────────────────────────────────────── */
let leafMap=null,simMarkers=[],simInterval=null,userMarker=null,destMarker=null,routePolyline=null;
let userLat=13.082,userLng=80.270;
 
function makeIcon(emoji,color,sz=36){
  return L.divIcon({
    html:`<div style="width:${sz}px;height:${sz}px;border-radius:50% 50% 50% 0;background:${color};display:flex;align-items:center;justify-content:center;font-size:${Math.round(sz*0.44)}px;box-shadow:0 4px 14px rgba(0,0,0,0.3);border:2.5px solid white;transform:rotate(-45deg)"><span style="transform:rotate(45deg)">${emoji}</span></div>`,
    iconSize:[sz,sz],iconAnchor:[sz/2,sz],popupAnchor:[0,-sz+4],className:''
  });
}
 
function haversine(lat1,lon1,lat2,lon2){
  const R=6371,dLat=(lat2-lat1)*Math.PI/180,dLon=(lon2-lon1)*Math.PI/180;
  const a=Math.sin(dLat/2)**2+Math.cos(lat1*Math.PI/180)*Math.cos(lat2*Math.PI/180)*Math.sin(dLon/2)**2;
  return R*2*Math.atan2(Math.sqrt(a),Math.sqrt(1-a));
}
 
function updateDistPanel(lat,lng){
  const dist=haversine(lat,lng,SAIRAM.lat,SAIRAM.lng);
  const dEl=document.getElementById('distanceVal'),eEl=document.getElementById('etaVal');
  if(dEl)dEl.textContent=dist.toFixed(2)+' km away';
  if(eEl){const m=Math.round((dist/40)*60);eEl.textContent=m<60?`${m} min`:`${Math.floor(m/60)}h ${m%60}m`;}
  if(leafMap){if(routePolyline)routePolyline.remove();routePolyline=L.polyline([[lat,lng],[SAIRAM.lat,SAIRAM.lng]],{color:'#c9a060',weight:4,opacity:0.75,dashArray:'8 6'}).addTo(leafMap);}
}
 
function initMap(){
  if(leafMap)return;
  leafMap=L.map('map',{zoomControl:true,attributionControl:true});
  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png',{attribution:'© OpenStreetMap contributors',maxZoom:19}).addTo(leafMap);
  destMarker=L.marker([SAIRAM.lat,SAIRAM.lng],{icon:makeIcon('🏫','#8c3535',40)}).addTo(leafMap)
    .bindPopup('<div style="font-family:DM Sans,sans-serif;min-width:175px"><strong>🏫 Sairam Polytechnic College</strong><br><span style="font-size:12px;color:#888">West Chennai, Tamil Nadu</span><br><span style="font-size:11px;color:#a07840">📍 13.0358°N, 80.0911°E</span></div>').openPopup();
  if(navigator.geolocation){
    navigator.geolocation.getCurrentPosition(
      pos=>{userLat=pos.coords.latitude;userLng=pos.coords.longitude;setupMap(userLat,userLng,'Your GPS Location');},
      ()=>setupMap(userLat,userLng,'Chennai Central (Simulated)')
    );
  } else setupMap(userLat,userLng,'Chennai Central (Simulated)');
}
 
function setupMap(lat,lng,locName){
  leafMap.fitBounds(L.latLngBounds([[lat,lng],[SAIRAM.lat,SAIRAM.lng]]),{padding:[60,60]});
  if(userMarker)userMarker.remove();
  userMarker=L.marker([lat,lng],{icon:makeIcon('📍','#c9a060',38)}).addTo(leafMap)
    .bindPopup(`<div style="font-family:DM Sans,sans-serif"><strong>Fleet Base</strong><br><span style="font-size:12px;color:#888">${locName}</span></div>`);
  document.getElementById('trackLoc').textContent=locName;
  document.getElementById('trackCoord').textContent=`${lat.toFixed(4)}°N, ${lng.toFixed(4)}°E`;
  document.getElementById('trackTime').textContent=new Date().toLocaleTimeString();
  updateDistPanel(lat,lng);
  placeVehicleMarkers(lat,lng);
}
 
function placeVehicleMarkers(baseLat,baseLng){
  simMarkers.forEach(m=>m.marker.remove());simMarkers=[];
  const list=vehicles.length?vehicles.slice(0,8):[{num:'FX-DEMO',type:'Bus'}];
  list.forEach(v=>{
    const lat=baseLat+(Math.random()-0.5)*0.055,lng=baseLng+(Math.random()-0.5)*0.055;
    const marker=L.marker([lat,lng],{icon:makeIcon('🚚','#4a7c59',34)}).addTo(leafMap)
      .bindPopup(`<div style="font-family:DM Sans,sans-serif"><strong>${v.num}</strong><br>${v.type||'Vehicle'}<br><span style="color:green;font-size:12px">● Active</span></div>`);
    simMarkers.push({marker,lat,lng});
  });
  if(simInterval)clearInterval(simInterval);
  simInterval=setInterval(()=>{
    simMarkers.forEach(o=>{o.lat+=(Math.random()-0.5)*0.002;o.lng+=(Math.random()-0.5)*0.002;o.marker.setLatLng([o.lat,o.lng]);});
    userLat+=(Math.random()-0.5)*0.0004;userLng+=(Math.random()-0.5)*0.0004;
    if(userMarker)userMarker.setLatLng([userLat,userLng]);
    updateDistPanel(userLat,userLng);
    document.getElementById('trackCoord').textContent=`${userLat.toFixed(4)}°N, ${userLng.toFixed(4)}°E`;
    document.getElementById('trackTime').textContent=new Date().toLocaleTimeString();
  },4000);
}
 
/* ── CLOCK ── */
setInterval(()=>{const el=document.getElementById('clockBadge');if(el)el.textContent=new Date().toLocaleTimeString('en-US',{hour:'2-digit',minute:'2-digit',second:'2-digit'});},1000);
 
/* ── INIT ── */
function initApp(){
  renderVehicles();renderDrivers();renderRoutes();renderIssues();
  renderDashboard();renderActivity();updateDropdowns();initCharts();
  if(!actLog.length)logActivity('FleetXpress initialized','act-info');
}
 
// restore theme
applyTheme(localStorage.getItem('fx_theme')||'light');
 
// auto-login
if(localStorage.getItem('fx_auth')){
  document.getElementById('loginPage').style.display='none';
  document.getElementById('app').style.display='block';
  initApp();
}
 
